 12â†’// Claims extends jwt.RegisteredClaims with application-specific fields.
 13â†’type Claims struct {
 14â†’	jwt.RegisteredClaims
 15â†’	Email        string         `json:"email,omitempty"`
 16â†’	Roles        []string       `json:"roles,omitempty"`
 17â†’	Role         string         `json:"role,omitempty"`          // Supabase: "authenticated", "anon", etc.
 18â†’	TeamID       string         `json:"team_id,omitempty"`
 19â†’	ClientType   string         `json:"client_type,omitempty"`   // web|cli|mobile|desktop
 20â†’	AppMetadata  map[string]any `json:"app_metadata,omitempty"`  // Supabase: provider info
 21â†’	UserMetadata map[string]any `json:"user_metadata,omitempty"` // Supabase: user profile data
 22â†’}
 23â†’
 24â†’// NormalizedRoles returns a deduplicated union of Roles and the singular Role field.
 25â†’func (c *Claims) NormalizedRoles() []string {
 26â†’	seen := make(map[string]struct{}, len(c.Roles)+1)
 27â†’	var result []string
 28â†’	for _, r := range c.Roles {
 29â†’		if _, ok := seen[r]; !ok {
 30â†’			seen[r] = struct{}{}
 31â†’			result = append(result, r)
 32â†’		}
 33â†’	}
 34â†’	if c.Role != "" {
 35â†’		if _, ok := seen[c.Role]; !ok {
 36â†’			result = append(result, c.Role)
 37â†’		}
 38â†’	}
 39â†’	return result
 40â†’}
 41â†’
 42â†’// Provider extracts the authentication provider from AppMetadata.
 43â†’// Returns an empty string if the provider is not set or is not a string.
 44â†’func (c *Claims) Provider() string {
 45â†’	if c.AppMetadata == nil {
 46â†’		return ""
 47â†’	}
 48â†’	p, _ := c.AppMetadata["provider"].(string)
 49â†’	return p
 50â†’}
