 52â†’// Validator validates a JWT token string and returns parsed claims.
 53â†’type Validator interface {
 54â†’	Validate(tokenString string) (*Claims, error)
 55â†’}
 56â†’
 57â†’// HMACValidator validates HS256 tokens using a shared secret.
 58â†’type HMACValidator struct {
 59â†’	secret     []byte
 60â†’	parserOpts []jwt.ParserOption
 61â†’}
 62â†’
 63â†’// NewHMACValidator creates a Validator using HS256 with the provided secret.
 64â†’// It returns an error if the secret is empty or contains only whitespace.
 65â†’func NewHMACValidator(secret string, opts ...jwt.ParserOption) (*HMACValidator, error) {
 66â†’	if strings.TrimSpace(secret) == "" {
 67â†’		return nil, errors.New("auth: HMAC secret must not be empty or whitespace-only")
 68â†’	}
 69â†’	return &HMACValidator{
 70â†’		secret:     []byte(secret),
 71â†’		parserOpts: opts,
 72â†’	}, nil
 73â†’}
 74â†’
 75â†’// Validate parses and validates an HS256 JWT token string.
 76â†’func (v *HMACValidator) Validate(tokenString string) (*Claims, error) {
 77â†’	claims := &Claims{}
 78â†’	token, err := jwt.ParseWithClaims(tokenString, claims, func(t *jwt.Token) (any, error) {
 79â†’		if _, ok := t.Method.(*jwt.SigningMethodHMAC); !ok {
 80â†’			return nil, fmt.Errorf("auth: unexpected signing method: %v", t.Header["alg"])
 81â†’		}
 82â†’		return v.secret, nil
 83â†’	}, v.parserOpts...)
 84â†’	if err != nil {
 85â†’		return nil, fmt.Errorf("auth: token validation failed: %w", err)
 86â†’	}
 87â†’	if !token.Valid {
 88â†’		return nil, errors.New("auth: token is not valid")
 89â†’	}
 90â†’	return claims, nil
 91â†’}
 92â†’
 93â†’// RSAValidator validates RS256 tokens using an RSA public key.
 94â†’type RSAValidator struct {
 95â†’	publicKey  *rsa.PublicKey
 96â†’	parserOpts []jwt.ParserOption
 97â†’}
 98â†’
 99â†’// NewRSAValidator creates a Validator using RS256 with the provided PEM public key.
100â†’func NewRSAValidator(pemPublicKey string, opts ...jwt.ParserOption) (*RSAValidator, error) {
101â†’	key, err := jwt.ParseRSAPublicKeyFromPEM([]byte(pemPublicKey))
102â†’	if err != nil {
103â†’		return nil, fmt.Errorf("auth: failed to parse RSA public key: %w", err)
104â†’	}
105â†’	return &RSAValidator{
106â†’		publicKey:  key,
107â†’		parserOpts: opts,
108â†’	}, nil
109â†’}
110â†’
111â†’// Validate parses and validates an RS256 JWT token string.
112â†’func (v *RSAValidator) Validate(tokenString string) (*Claims, error) {
113â†’	claims := &Claims{}
114â†’	token, err := jwt.ParseWithClaims(tokenString, claims, func(t *jwt.Token) (any, error) {
115â†’		if _, ok := t.Method.(*jwt.SigningMethodRSA); !ok {
116â†’			return nil, fmt.Errorf("auth: unexpected signing method: %v", t.Header["alg"])
117â†’		}
118â†’		return v.publicKey, nil
119â†’	}, v.parserOpts...)
120â†’	if err != nil {
121â†’		return nil, fmt.Errorf("auth: token validation failed: %w", err)
122â†’	}
123â†’	if !token.Valid {
124â†’		return nil, errors.New("auth: token is not valid")
125â†’	}
126â†’	return claims, nil
127â†’}
