27â†’// Logging logs each request with method, path, status, duration, and request ID.
28â†’func Logging(next http.Handler) http.Handler {
29â†’	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
30â†’		start := time.Now()
31â†’		rw := &responseWriter{ResponseWriter: w, status: http.StatusOK}
32â†’
33â†’		next.ServeHTTP(rw, r)
34â†’
35â†’		attrs := []any{
36â†’			"method", r.Method,
37â†’			"path", r.URL.Path,
38â†’			"status", rw.status,
39â†’			"duration_ms", time.Since(start).Milliseconds(),
40â†’			"bytes", rw.bytes,
41â†’			"request_id", requestIDFromContext(r.Context()),
42â†’			"remote_addr", r.RemoteAddr,
43â†’		}
44â†’		if q := r.URL.RawQuery; q != "" {
45â†’			attrs = append(attrs, "query", q)
46â†’		}
47â†’		if ua := r.UserAgent(); ua != "" {
48â†’			attrs = append(attrs, "user_agent", ua)
49â†’		}
50â†’		slog.InfoContext(r.Context(), "request", attrs...)
51â†’	})
52â†’}
