 1â†’package middleware
 2â†’
 3â†’import (
 4â†’	"fmt"
 5â†’	"net"
 6â†’	"net/http"
 7â†’	"strings"
 8â†’)
 9â†’
10â†’// IPAllowlist returns middleware that restricts access to the given CIDR ranges.
11â†’// Requests from IPs not in any CIDR receive 403 Forbidden.
12â†’func IPAllowlist(cidrs []*net.IPNet) func(http.Handler) http.Handler {
13â†’	return func(next http.Handler) http.Handler {
14â†’		return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
15â†’			ip := clientIP(r)
16â†’			if ip == nil || !matchesCIDR(ip, cidrs) {
17â†’				http.Error(w, "forbidden", http.StatusForbidden)
18â†’				return
19â†’			}
20â†’			next.ServeHTTP(w, r)
21â†’		})
22â†’	}
23â†’}
24â†’
25â†’// ParseCIDRs splits a comma-separated list of CIDR strings and parses each one.
26â†’func ParseCIDRs(raw string) ([]*net.IPNet, error) {
27â†’	var nets []*net.IPNet
28â†’	for _, s := range strings.Split(raw, ",") {
29â†’		s = strings.TrimSpace(s)
30â†’		if s == "" {
31â†’			continue
32â†’		}
33â†’		_, ipNet, err := net.ParseCIDR(s)
34â†’		if err != nil {
35â†’			return nil, fmt.Errorf("middleware: invalid CIDR %q: %w", s, err)
36â†’		}
37â†’		nets = append(nets, ipNet)
38â†’	}
39â†’	return nets, nil
40â†’}
41â†’
42â†’// clientIP extracts the client IP from the request. It uses RemoteAddr,
43â†’// which chi's RealIP middleware has already resolved from X-Forwarded-For
44â†’// or X-Real-IP headers.
45â†’func clientIP(r *http.Request) net.IP {
46â†’	host, _, err := net.SplitHostPort(r.RemoteAddr)
47â†’	if err != nil {
48â†’		// RemoteAddr might be an IP without port
49â†’		return net.ParseIP(r.RemoteAddr)
50â†’	}
51â†’	return net.ParseIP(host)
52â†’}
53â†’
54â†’func matchesCIDR(ip net.IP, cidrs []*net.IPNet) bool {
55â†’	for _, cidr := range cidrs {
56â†’		if cidr.Contains(ip) {
57â†’			return true
58â†’		}
59â†’	}
60â†’	return false
61â†’}
