  1â†’package middleware
  2â†’
  3â†’import (
  4â†’	"log/slog"
  5â†’	"net/http"
  6â†’	"strings"
  7â†’	"sync/atomic"
  8â†’
  9â†’	"github.com/ketang/kapow/api/internal/config"
 10â†’)
 11â†’
 12â†’var defaultSensitiveHeaders = map[string]struct{}{
 13â†’	"Authorization": {},
 14â†’	"Cookie":        {},
 15â†’	"Set-Cookie":    {},
 16â†’	"X-Api-Key":     {},
 17â†’}
 18â†’
 19â†’const redactedValue = "[REDACTED]"
 20â†’
 21â†’// HTTPDetailConfig holds the settings for HTTP debug logging.
 22â†’// It is designed to be swapped at runtime via atomic.Pointer so that
 23â†’// a future admin endpoint can change debug verbosity without a restart.
 24â†’type HTTPDetailConfig struct {
 25â†’	RequestHeaders  string   // "none" | "selected" | "all"
 26â†’	SelectedHeaders []string // pre-parsed header names
 27â†’	RedactSensitive bool
 28â†’	ResponseMode    string // "none" | "headers" | "full"
 29â†’	BodyMaxBytes    int
 30â†’}
 31â†’
 32â†’// NewHTTPDetailConfig builds an HTTPDetailConfig from the application Config.
 33â†’func NewHTTPDetailConfig(cfg *config.Config) *HTTPDetailConfig {
 34â†’	return &HTTPDetailConfig{
 35â†’		RequestHeaders:  cfg.HTTPDebugRequestHeaders,
 36â†’		SelectedHeaders: cfg.ParsedSelectedHeaders(),
 37â†’		RedactSensitive: cfg.HTTPDebugRedactSensitive,
 38â†’		ResponseMode:    cfg.HTTPDebugResponseMode,
 39â†’		BodyMaxBytes:    cfg.HTTPDebugBodyMaxBytes,
 40â†’	}
 41â†’}
 42â†’
 43â†’// HTTPDetail logs request and/or response headers at Debug level.
 44â†’// The config is read from the atomic pointer on every request, allowing
 45â†’// hot-reload without restarting the server.
 46â†’func HTTPDetail(cfgPtr *atomic.Pointer[HTTPDetailConfig]) func(http.Handler) http.Handler {
 47â†’	return func(next http.Handler) http.Handler {
 48â†’		return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
 49â†’			dc := cfgPtr.Load()
 50â†’
 51â†’			// Fast path: no-op when everything is off.
 52â†’			if dc.RequestHeaders == "none" && dc.ResponseMode == "none" {
 53â†’				next.ServeHTTP(w, r)
 54â†’				return
 55â†’			}
 56â†’
 57â†’			// Log request headers before calling next handler.
 58â†’			if dc.RequestHeaders != "none" {
 59â†’				attrs := []any{
 60â†’					"component", "http.detail",
 61â†’					"request_id", requestIDFromContext(r.Context()),
 62â†’					"method", r.Method,
 63â†’					"path", r.URL.Path,
 64â†’				}
 65â†’				attrs = append(attrs, buildRequestHeaderAttrs(r.Header, dc.RequestHeaders, dc.SelectedHeaders, dc.RedactSensitive)...)
 66â†’				slog.DebugContext(r.Context(), "http.detail: request headers", attrs...)
 67â†’			}
 68â†’
 69â†’			// Wrap ResponseWriter when full response logging is requested.
 70â†’			cw := w
 71â†’			var bc *bodyCapture
 72â†’			if dc.ResponseMode == "full" {
 73â†’				bc = newBodyCapture(w, dc.BodyMaxBytes)
 74â†’				cw = bc
 75â†’			}
 76â†’
 77â†’			next.ServeHTTP(cw, r)
 78â†’
 79â†’			// Log response headers (and optionally body) after handler returns.
 80â†’			if dc.ResponseMode != "none" {
 81â†’				attrs := []any{
 82â†’					"component", "http.detail",
 83â†’					"request_id", requestIDFromContext(r.Context()),
 84â†’				}
 85â†’				attrs = append(attrs, buildResponseHeaderAttrs(cw.Header(), dc.RedactSensitive)...)
 86â†’				if dc.ResponseMode == "full" && bc != nil {
 87â†’					attrs = append(attrs,
 88â†’						"response_body_bytes", bc.captured,
 89â†’						"response_body_truncated", bc.truncated,
 90â†’						"response_body", string(bc.buf),
 91â†’					)
 92â†’				}
 93â†’				slog.DebugContext(r.Context(), "http.detail: response", attrs...)
 94â†’			}
 95â†’		})
 96â†’	}
 97â†’}
 98â†’
 99â†’// buildRequestHeaderAttrs converts request headers into slog key-value pairs.
100â†’func buildRequestHeaderAttrs(h http.Header, mode string, selected []string, redact bool) []any {
101â†’	var attrs []any
102â†’	switch mode {
103â†’	case "all":
104â†’		for name, values := range h {
105â†’			val := strings.Join(values, ", ")
106â†’			if redact && isSensitiveHeader(name) {
107â†’				val = redactedValue
108â†’			}
109â†’			attrs = append(attrs, "req."+name, val)
110â†’		}
111â†’	case "selected":
112â†’		for _, name := range selected {
113â†’			canonical := http.CanonicalHeaderKey(name)
114â†’			values := h.Values(canonical)
115â†’			if len(values) == 0 {
116â†’				continue
117â†’			}
118â†’			val := strings.Join(values, ", ")
119â†’			if redact && isSensitiveHeader(canonical) {
120â†’				val = redactedValue
121â†’			}
122â†’			attrs = append(attrs, "req."+canonical, val)
123â†’		}
124â†’	}
125â†’	return attrs
126â†’}
127â†’
128â†’// buildResponseHeaderAttrs converts response headers into slog key-value pairs.
129â†’func buildResponseHeaderAttrs(h http.Header, redact bool) []any {
130â†’	var attrs []any
131â†’	for name, values := range h {
132â†’		val := strings.Join(values, ", ")
133â†’		if redact && isSensitiveHeader(name) {
134â†’			val = redactedValue
135â†’		}
136â†’		attrs = append(attrs, "resp."+name, val)
137â†’	}
138â†’	return attrs
139â†’}
140â†’
141â†’// isSensitiveHeader reports whether the given header name is sensitive.
142â†’func isSensitiveHeader(name string) bool {
143â†’	_, ok := defaultSensitiveHeaders[http.CanonicalHeaderKey(name)]
144â†’	return ok
145â†’}
146â†’
147â†’// bodyCapture wraps an http.ResponseWriter and tees written bytes
148â†’// into an internal buffer up to a configurable maximum.
149â†’type bodyCapture struct {
150â†’	http.ResponseWriter
151â†’	buf       []byte
152â†’	captured  int
153â†’	maxBytes  int
154â†’	truncated bool
155â†’}
156â†’
157â†’func newBodyCapture(w http.ResponseWriter, maxBytes int) *bodyCapture {
158â†’	return &bodyCapture{
159â†’		ResponseWriter: w,
160â†’		buf:            make([]byte, 0, maxBytes),
161â†’		maxBytes:       maxBytes,
162â†’	}
163â†’}
164â†’
165â†’func (bc *bodyCapture) Write(b []byte) (int, error) {
166â†’	if bc.captured < bc.maxBytes {
167â†’		remaining := bc.maxBytes - bc.captured
168â†’		toCapture := len(b)
169â†’		if toCapture > remaining {
170â†’			toCapture = remaining
171â†’			bc.truncated = true
172â†’		}
173â†’		bc.buf = append(bc.buf, b[:toCapture]...)
174â†’		bc.captured += toCapture
175â†’	} else if !bc.truncated {
176â†’		bc.truncated = true
177â†’	}
178â†’	return bc.ResponseWriter.Write(b)
179â†’}
180â†’
181â†’func (bc *bodyCapture) Unwrap() http.ResponseWriter {
182â†’	return bc.ResponseWriter
183â†’}
184â†’

